---- MY PROGRAMS ----
---------------------

-- Set programs that you use
local terminal = "kitty"
local fileManager = "dolphin"
local menu = "wofi --show drun"


-------------------
---- AUTOSTART ----
-------------------

-- See https://wiki.hypr.land/Configuring/Basics/Autostart/
-- Autostart necessary processes (like notification daemons, status bars, etc.)
-- hl.on("hyprland.start") ensures these only run once at boot, not on every config reload.

hl.on("hyprland.start", function()
    -- hl.exec_cmd("sleep 2 && hyprctl dispatch dpms off && sleep 0.5 && hyprctl dispatch dpms on")
    -- hl.exec_cmd(terminal)
    -- hl.exec_cmd("nm-applet")
    -- hl.exec_cmd("waybar & hyprpaper & firefox")
    hl.exec_cmd("swww-daemon") -- was "awww-daemon" — that package doesn't exist, this is likely what you meant
    hl.exec_cmd("wayle panel start")
    hl.exec_cmd("~/.config/hypr/scripts/wallpaper.sh")
end)


